    {
        // Hacker News Search via Algolia API (free, no key)
        // Note: points cannot be used as an API numeric filter (not in numericAttributesForFiltering).
        // min_points is applied client-side. Only created_at_i is server-side filterable.

        $timeout = min(30, max(5, $timeout ?? 15));
        $query = $query ?? '';
        $tags = $tags ?? 'story';
        $hitsPerPage = min(50, max(1, $hits_per_page ?? 10));
        $page = max(0, $page ?? 0);
        $sortBy = $sort_by ?? 'relevance';
        $includeContent = $include_content ?? false;
        $minPoints = $min_points ?? null;

        if (empty(trim($query))) {
            return ['success' => false, 'error' => 'Search query is required.', 'query' => $query];
        }

        try {
            // Determine endpoint based on sort
            if ($sortBy === 'date') {
                $baseUrl = 'https://hn.algolia.com/api/v1/search_by_date';
            } else {
                $baseUrl = 'https://hn.algolia.com/api/v1/search';
            }

            $params = [
                'query' => $query,
                'hitsPerPage' => $hitsPerPage,
                'page' => $page,
            ];

            // Tags — simple comma-separated
            if (!empty($tags)) {
                $params['tags'] = $tags;
            }

            // Numeric filters (only created_at_i is filterable)
            $numericFilters = [];
            if (!empty($numeric_filter)) {
                $numericFilters[] = $numeric_filter;
            }
            // Date range
            if (!empty($date_from) || !empty($date_to)) {
                if (!empty($date_from)) {
                    $ts = strtotime($date_from);
                    if ($ts !== false) {
                        $numericFilters[] = 'created_at_i>=' . $ts;
